package main

import (
	"crypto/rand"
	"encoding/base64"
	"fmt"
	"net/http"
	"strings"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback", // Fixed pre-registered redirect URI
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter specifies where to redirect the user AFTER the OAuth callback completes.
// Security notes:
// 1. Uses cryptographically secure state parameter to prevent CSRF
// 2. Validates redirectPath to prevent open redirect attacks
// 3. Uses fixed pre-registered RedirectURL from OAuthConfig (never overridden)
// 4. Sets secure cookie attributes with short expiration
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate redirectPath to prevent open redirect vulnerabilities
	// Must be non-empty relative path starting with single '/', no newlines, no protocol-relative sequences
	if redirectPath == "" {
		redirectPath = "/"
	}
	if !strings.HasPrefix(redirectPath, "/") {
		return "", fmt.Errorf("invalid redirectPath: must be absolute path starting with '/'")
	}
	if strings.ContainsAny(redirectPath, "\r\n") {
		return "", fmt.Errorf("invalid redirectPath: contains illegal newline characters")
	}
	if len(redirectPath) > 1 && redirectPath[1] == '/' {
		return "", fmt.Errorf("invalid redirectPath: must not start with // (protocol-relative URL)")
	}
	// Additional safety: reject paths containing scheme indicators
	if strings.Contains(redirectPath, ":") && !strings.HasPrefix(redirectPath, "/:") {
		return "", fmt.Errorf("invalid redirectPath: contains potential URL scheme")
	}

	// Generate cryptographically secure state parameter (CSRF protection)
	stateBytes := make([]byte, 32)
	if _, err := rand.Read(stateBytes); err != nil {
		return "", fmt.Errorf("failed to generate state parameter: %w", err)
	}
	state := base64.URLEncoding.EncodeToString(stateBytes)

	// Set state cookie with strict security attributes and short expiration
	stateCookie := &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,   // Prevent JavaScript access
		Secure:   true,   // Require HTTPS
		SameSite: http.SameSiteLaxMode, // Allow cookie on top-level navigation (OAuth callback)
		Path:     "/",
		MaxAge:   600,    // 10 minutes expiration (limits CSRF window)
	}
	http.SetCookie(w, stateCookie)

	// Store validated post-auth redirect path in separate secure cookie
	// Callback handler will use this AFTER successful token exchange
	redirectCookie := &http.Cookie{
		Name:     "oauth_redirect_path",
		Value:    redirectPath,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
		MaxAge:   600,
	}
	http.SetCookie(w, redirectCookie)

	// CRITICAL: Use ORIGINAL OAuthConfig with PRE-REGISTERED RedirectURL
	// NEVER override RedirectURL with user input (prevents open redirect attacks)
	authURL := OAuthConfig.AuthCodeURL(state, oauth2.AccessTypeOnline)

	return authURL, nil
}

