	randomBytes := make([]byte, 32)
	if _, err := rand.Read(randomBytes); err != nil {
		return "", err
	}
	randomStr := base64.URLEncoding.EncodeToString(randomBytes)

	// Combine random state and sanitized redirectPath; encode for safe transport
	stateData := randomStr + "|" + redirectPath
	stateParam := base64.URLEncoding.EncodeToString([]byte(stateData))

	// Set secure cookie containing state+redirectPath for later validation and redirection
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    stateParam,
		HttpOnly: true,
		Secure:   true, // Requires HTTPS; aligns with OAuth2 security best practices
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
