		hostWithoutPort := strings.Split(redirectURL.Host, ":")[0]
		if hostWithoutPort != "localhost" && 
		   hostWithoutPort != "127.0.0.1" && 
		   hostWithoutPort != "::1" {
			return "", fmt.Errorf("redirect URL must use HTTPS")
		}
	}

